const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const norm = (s) => (s || '').replace(/\u00a0/g, ' ').replace(/\s+/g, ' ').trim();
const decodeCk = (href) => {
  if (!href) return null;
  try {
    const u = new URL(href, 'https://www.bing.com');
    if (!/\/ck\/a/i.test(u.pathname)) return href;
    let raw = u.searchParams.get('u');
    if (!raw) return href;
    if (raw.startsWith('a1')) raw = raw.slice(2);
    raw = raw.replace(/-/g, '+').replace(/_/g, '/');
    while (raw.length % 4) raw += '=';
    const decoded = atob(raw);
    return /^https?:\/\//i.test(decoded) ? decoded : href;
  } catch (e) { return href; }
};
const items = Array.from(document.querySelectorAll('ol#b_results > li.b_algo')).slice(0, 10);
return items.map((it) => {
  const a = it.querySelector('h2 a');
  const title = a ? norm(a.textContent) : null;
  const rawHref = a ? a.getAttribute('href') : null;
  const url = decodeCk(rawHref);
  const citeEl = it.querySelector('cite');
  const source = citeEl ? norm(citeEl.textContent) : null;
  const snipEl = it.querySelector('div.b_caption p, p.b_lineclamp2, p.b_lineclamp3, p.b_lineclamp4, p');
  const snippet = snipEl ? norm(snipEl.textContent) : null;
  return { title, url, source, snippet };
}).filter((r) => r.title && r.url);
